"use strict";parserFactory.registerUrlRule(t=>util.extractHostName(t).endsWith(".tumblr.com"),()=>new TumblrParser);class TumblrParser extends Parser{constructor(){super()}async getChapterUrls(t){let e=this.findContent(t);return this.removeUnwantedContent(e),util.hyperlinksToChapterList(e)}findContent(t){let e=t.querySelector("main div.post")||t.querySelector("main div.post-main")||t.querySelector("article div.post-content");for(let t of e.querySelectorAll("a[data-big-photo]"))t.href=t.dataset?.bigPhoto;return e}async fetchChapter(t){let e=(await HttpClient.wrapFetch(t)).responseXML;this.removeUnwantedContent(this.findContent(e));let r=e.querySelector("iframe.photoset");if(null!==r){let t=(await HttpClient.wrapFetch(r.src)).responseXML.querySelector("div.photoset");null===t?this.fixupPhotoset(e):r.replaceWith(t)}return e}removeUnwantedContent(t){util.removeChildElementsMatchingSelector(t,"footer, #disqus_thread, #notes")}fixupPhotoset(t){let e=t.querySelector("div.html_photoset");if(null!==e)for(let r of this.getPhotosetUrls(t)){let t=document.createElement("img");t.src=r,e.appendChild(t)}}getPhotosetUrls(t){return[...t.querySelectorAll("meta[property='og:image']")].map(t=>t.getAttribute("content")).filter(t=>!util.isNullOrEmpty(t))}}